const checks = {
  "1. [data-certeza] count === 7": document.querySelectorAll('#periodo-nacional [data-certeza]').length === 7,
  "2. .card-image img count === 7": document.querySelectorAll('#periodo-nacional .card-image img').length === 7,
  "3. events-grid--certeza present": document.querySelector('#periodo-nacional .events-grid--certeza') !== null,
  "4. alberdi-quote count >= 1": document.querySelectorAll('#periodo-nacional .alberdi-quote').length >= 1,
  "5. cite count >= 7": document.querySelectorAll('#periodo-nacional cite').length >= 7,
  "6. img-error/fallback === 0": document.querySelectorAll('#periodo-nacional .img-error, #periodo-nacional .img-fallback').length === 0,
  "7. no placeholders": document.querySelectorAll('#periodo-nacional .event-card--placeholder').length === 0,
  "8. stagger delays correct": JSON.stringify(Array.from(document.querySelectorAll('#periodo-nacional .events-grid--certeza article')).map(e => e.style.getPropertyValue('--reveal-delay'))) === '["0ms","80ms","160ms","240ms","320ms","400ms","480ms"]',
  "9. certeza distribution correct": JSON.stringify(Array.from(document.querySelectorAll('#periodo-nacional [data-certeza]')).map(e => e.dataset.certeza)) === '["hecho","hecho","hecho","hecho","hecho","hecho","opinion"]'
};
const allPass = Object.values(checks).every(Boolean);
JSON.stringify({allPass, checks}, null, 2);

